"use client"; import { useEffect, useState } from "react"; import AuthGuard from "@/components/AuthGuard"; import PageHeader from "@/components/PageHeader"; import DashboardShell from "@/components/DashboardShell"; import { messageApi, MessageThread, Message } from "@/lib/api"; export default function MessagesPage() { const [threads, setThreads] = useState<MessageThread[]>([]); const [selected, setSelected] = useState<MessageThread | null>(null); const [messages, setMessages] = useState<Message[]>([]); const [text, setText] = useState(""); useEffect(() => { messageApi.inbox().then((r) => setThreads(r.threads)); }, []); const open = async (thread: MessageThread) => { setSelected(thread); const res = await messageApi.thread(thread.partner._id); setMessages(res.messages); }; const send = async () => { if (!selected || !text.trim()) return; await messageApi.send({ receiverId: selected.partner._id, text }); setText(""); open(selected); }; return <AuthGuard><PageHeader title="Messages" text="Communicate with platform users and sellers." /><DashboardShell><div className="grid grid-2"><div className="card card-pad"><h3 className="title-md">Inbox</h3>{threads.length === 0 ? <div className="empty">No threads</div> : threads.map((t) => <div key={t.partner._id} className="card card-pad" style={{ marginTop: 10, cursor: "pointer" }} onClick={() => open(t)}><strong>{t.partner.name}</strong><div className="muted">{t.lastMessage.text}</div></div>)}</div><div className="card card-pad"><h3 className="title-md">Conversation</h3>{!selected ? <div className="empty">Open a thread from inbox.</div> : <><div className="grid" style={{ marginTop: 10 }}>{messages.map((m) => <div key={m._id} className="card card-pad" style={{ background: "#f8fafc" }}>{m.text}</div>)}</div><div style={{ display: "flex", gap: 10, marginTop: 14 }}><input className="input" value={text} onChange={(e)=>setText(e.target.value)} placeholder="Write a message" /><button className="btn btn-primary" onClick={send}>Send</button></div></>}</div></div></DashboardShell></AuthGuard>; }
